    // If the input was not pre-arranged, a separate bit-reversal stage would be needed.

    // --- Main FFT Stages ---

    // 'stage' iterates over the log2(N) stages (0 to 5)
    for (int stage = 1; stage <= LOG_N; stage++) {

        // 'm' is the size of the butterfly group (2, 4, 8, ..., 64)
        int m = 1 << stage; 

        // 'k' iterates over the starting index of each butterfly group
        // k = 0, m, 2m, 3m, ...
