            // 'half_m' is the size of the sub-group (m/2)
            int half_m = m / 2;

            // 'j' iterates over the butterflies within the group
            for (int j = 0; j < half_m; j++) {

                // Index of the first element in the butterfly pair
                int idx_a = k + j;
                // Index of the second element in the butterfly pair
                int idx_b = k + j + half_m;

                // --- Twiddle Factor Calculation (W_m^j) ---
                // W_m^j = exp(-j * 2 * pi * j / m)
                // Angle = -2 * pi * j / m
