    {1, 2, 3, 2, 1},
    {2, 4, 6, 4, 2},
    {3, 6, 9, 6, 3},
    {2, 4, 6, 4, 2},
    {1, 2, 3, 2, 1}
};

/**
 * @brief Performs a 5x5 Gaussian blur on a 128x128 image.
 * 
 * @param image_in Input grayscale image (128x128).
 * @param image_out Output blurred image (128x128).
 */
void gaussian_blur(fixed_t image_in[HEIGHT][WIDTH], fixed_t image_out[HEIGHT][WIDTH]) {

    // Optimization: Partition the input and output arrays to allow parallel access
    // to rows and columns, which is crucial for high throughput.
    #pragma HLS INTERFACE m_axi port=image_in offset=slave depth=WIDTH*HEIGHT
    #pragma HLS INTERFACE m_axi port=image_out offset=slave depth=WIDTH*HEIGHT
    #pragma HLS INTERFACE s_axilite port=return

    // Partition the entire 2D arrays into individual elements (or small blocks)
    // This allows multiple reads/writes in parallel.
    #pragma HLS ARRAY_PARTITION variable=image_in complete dim=1
    #pragma HLS ARRAY_PARTITION variable=image_out complete dim=1

    // The outer loop iterates over the output pixels (y, x).
    // We start from 2 and end at WIDTH-3/HEIGHT-3 to ensure the full 5x5 kernel
    // stays within the image boundaries (handling borders by skipping them).
    for (int y = 1; y < HEIGHT - 1; y++) {
        // Optimization: Pipeline the outer loop (y)
        #pragma HLS PIPELINE II=1

        for (int x = 1; x < WIDTH - 1; x++) {
            // Optimization: Pipeline the inner loop (x)
            #pragma HLS PIPELINE II=1

            // Initialize the accumulator for the current output pixel
            fixed_t sum = 0;

            // Convolution loops: Iterate over the 5x5 kernel
            for (int ky = 0; ky < KERNEL_SIZE; ky++) {
                for (int kx = 0; kx < KERNEL_SIZE; kx++) {

                    // Calculate the coordinates for the input pixel
                    int input_y = y + (ky - KERNEL_SIZE / 2);
                    int input_x = x + (kx - KERNEL_SIZE / 2);

                    // Calculate the weighted sum: Kernel[ky][kx] * Input[y+ky][x+kx]
                    // Note: The kernel weights are fixed_t, and the input is fixed_t.
                    sum += gaussian_kernel[ky][kx] * image_in[input_y][input_x];
                }
            }

            // Store the result in the output image
            image_out[y][x] = sum;
        }
    }
